class Middleware:
    @staticmethod
    def before(input):
        request = input["request"]
        if request["headers"].get("x-blocked") == "true":
            return {
                "action": "respond",
                "status": 403,
                "headers": { "content-type": "application/json" },
                "body": { "detail": "blocked by Python middleware" },
            }
        return { "action": "continue" }

    @staticmethod
    def after(input):
        return {
            "headers": {
                "x-request-id": input["context"]["requestId"],
                "x-powered-by": "yon-python-middleware",
            }
        }

    @staticmethod
    def rateLimit(input):
        return {
            "allowed": True,
            "limit": 100,
            "remaining": 99,
            "resetAt": 1780000000000,
        }

import json
import sys
import time

input = json.load(sys.stdin)

if input["phase"] == "before":
    print(json.dumps({ "action": "continue" }))

if input["phase"] == "after":
    print(json.dumps({
        "headers": { "x-middleware-phase": "after" }
    }))

if input["phase"] == "rateLimit":
    print(json.dumps({
        "allowed": True,
        "limit": 100,
        "remaining": 99,
        "resetAt": int(time.time() * 1000) + 60000,
    }))

